{"content":"export const dynamic = 'force-dynamic';

import { createClient } from '@/lib/supabase/server';
import { notFound } from 'next/navigation';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ResponseChart } from '@/components/surveys/response-chart';
import { ClipboardList, ExternalLink, MessageSquare, Copy } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import Link from 'next/link';
import type { Survey, SurveyResponse } from '@/types';

export default async function SurveyDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const supabase = await createClient();

  const { data: survey } = await supabase
    .from('surveys')
    .select('*')
    .eq('id', id)
    .single();

  if (!survey) notFound();

  const typedSurvey = survey as Survey;

  const { data: responses } = await supabase
    .from('survey_responses')
    .select('*')
    .eq('survey_id', id)
    .order('created_at', { ascending: false });

  const typedResponses = (responses || []) as SurveyResponse[];
  const publicUrl = `${process.env.NEXT_PUBLIC_APP_URL || ''}/s/${id}`;

  return (
    <div className="space-y-6">
      <div className="flex items-start justify-between">
        <div className="flex items-start gap-4">
          <div className="rounded-lg bg-purple-50 dark:bg-purple-950 p-3">
            <ClipboardList className="h-6 w-6 text-purple-600 dark:text-purple-400" />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{typedSurvey.title}</h1>
            <p className="text-sm text-muted-foreground">
              {typedSurvey.questions.length} questions · {typedSurvey.response_count} responses
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant={typedSurvey.status === 'active' ? 'default' : 'secondary'}>
            {typedSurvey.status}
          </Badge>
          {typedSurvey.status === 'active' && (
            <Button variant="outline" size="sm" asChild>
              <Link href={publicUrl} target="_blank">
                <ExternalLink className="h-4 w-4 mr-1" />
                Preview
              </Link>
            </Button>
          )}
        </div>
      </div>

      {/* Share URL */}
      {typedSurvey.status === 'active' && (
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <div className="flex-1 bg-muted rounded-md px-3 py-2 text-sm font-mono truncate">
                {publicUrl}
              </div>
              <Button variant="outline" size="sm">
                <Copy className="h-4 w-4 mr-1" />
                Copy
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      <Tabs defaultValue="responses">
        <TabsList>
          <TabsTrigger value="responses">
            <MessageSquare className="h-4 w-4 mr-1" />
            Responses ({typedResponses.length})
          </TabsTrigger>
          <TabsTrigger value="charts">Charts</TabsTrigger>
          <TabsTrigger value="analysis">AI Analysis</TabsTrigger>
        </TabsList>

        <TabsContent value="responses" className="space-y-4 mt-4">
          {typedResponses.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <MessageSquare className="mx-auto h-8 w-8 mb-2 opacity-50" />
              <p className="text-sm">No responses yet</p>
              <p className="text-xs mt-1">Share the survey link to start collecting responses</p>
            </div>
          ) : (
            typedResponses.map((response) => (
              <Card key={response.id}>
                <CardContent className="p-4">
                  <div className="flex items-center justify-between mb-3">
                    <p className="text-xs text-muted-foreground">
                      {formatDistanceToNow(new Date(response.created_at), { addSuffix: true })}
                    </p>
                    {response.respondent_email && (
                      <p className="text-xs text-muted-foreground">{response.respondent_email}</p>
                    )}
                  </div>
                  <div className="space-y-2">
                    {typedSurvey.questions.map((q) => (
                      <div key={q.id} className="text-sm">
                        <p className="font-medium">{q.text}</p>
                        <p className="text-muted-foreground">
                          {response.answers[q.id] !== undefined
                            ? Array.isArray(response.answers[q.id])
                              ? (response.answers[q.id] as string[]).join(', ')
                              : String(response.answers[q.id])
                            : 'No answer'}
                        </p>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            ))
          )}
        </TabsContent>

        <TabsContent value="charts" className="mt-4">
          {typedResponses.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <p className="text-sm">Collect responses to see charts</p>
            </div>
          ) : (
            <div className="grid gap-4 md:grid-cols-2">
              {typedSurvey.questions.map((q) => (
                <ResponseChart
                  key={q.id}
                  question={q}
                  answers={typedResponses
                    .map((r) => r.answers[q.id])
                    .filter((a) => a !== undefined && a !== null)}
                />
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="analysis" className="mt-4">
          <AnalysisTab surveyId={id} />
        </TabsContent>
      </Tabs>
    </div>
  );
}

// Client component for analysis tab
async function AnalysisTab({ surveyId }: { surveyId: string }) {
  const supabase = await createClient();

  const { data: analysis } = await supabase
    .from('analyses')
    .select('*')
    .eq('survey_id', surveyId)
    .order('created_at', { ascending: false })
    .limit(1)
    .single();

  if (!analysis) {
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground mb-4">No analysis yet</p>
        <AnalyzeButton surveyId={surveyId} />
      </div>
    );
  }

  // Import and use AnalysisReport dynamically to use the component
  const { AnalysisReport } = await import('@/components/surveys/analysis-report');
  return (
    <div className="space-y-4">
      <div className="flex justify-end">
        <AnalyzeButton surveyId={surveyId} label="Re-analyze" />
      </div>
      <AnalysisReport results={analysis.results} />
    </div>
  );
}

// Simple client button for triggering analysis
function AnalyzeButton({ surveyId, label = 'Run AI Analysis' }: { surveyId: string; label?: string }) {
  return (
    <form action={`/api/surveys/${surveyId}/analyze`} method="POST">
      <Button type="submit">{label}</Button>
    </form>
  );
}
"}

{"content":"'use client';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';
import type { AnalysisResults } from '@/types';

const SENTIMENT_COLORS = {
  positive: '#10b981',
  neutral: '#6b7280',
  negative: '#ef4444',
};

interface AnalysisReportProps {
  results: AnalysisResults;
}

export function AnalysisReport({ results }: AnalysisReportProps) {
  const sentimentData = [
    { name: 'Positive', value: Math.round(results.sentiment.positive * 100) },
    { name: 'Neutral', value: Math.round(results.sentiment.neutral * 100) },
    { name: 'Negative', value: Math.round(results.sentiment.negative * 100) },
  ];

  return (
    <div className="space-y-6">
      {/* Summary */}
      <Card>
        <CardHeader>
          <CardTitle>Executive Summary</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground leading-relaxed">{results.summary}</p>
        </CardContent>
      </Card>

      <div className="grid gap-6 md:grid-cols-2">
        {/* Sentiment */}
        <Card>
          <CardHeader>
            <CardTitle>Sentiment Distribution</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={250}>
              <PieChart>
                <Pie
                  data={sentimentData}
                  dataKey="value"
                  nameKey="name"
                  cx="50%"
                  cy="50%"
                  outerRadius={80}
                  label={({ name, value }) => `${name}: ${value}%`}
                >
                  <Cell fill={SENTIMENT_COLORS.positive} />
                  <Cell fill={SENTIMENT_COLORS.neutral} />
                  <Cell fill={SENTIMENT_COLORS.negative} />
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* NPS */}
        {results.nps_score !== undefined && (
          <Card>
            <CardHeader>
              <CardTitle>NPS Score</CardTitle>
              <CardDescription>Net Promoter Score</CardDescription>
            </CardHeader>
            <CardContent className="flex items-center justify-center">
              <div className="text-center">
                <div className={`text-6xl font-bold ${
                  results.nps_score >= 50 ? 'text-green-600' :
                  results.nps_score >= 0 ? 'text-yellow-600' : 'text-red-600'
                }`}>
                  {results.nps_score}
                </div>
                <p className="text-sm text-muted-foreground mt-2">
                  {results.nps_score >= 50 ? 'Excellent' :
                   results.nps_score >= 0 ? 'Good' : 'Needs Improvement'}
                </p>
              </div>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Themes */}
      {results.themes.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>Key Themes</CardTitle>
            <CardDescription>Automatically detected topics from responses</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {results.themes.map((theme, index) => (
                <div key={index} className="border rounded-lg p-4">
                  <div className="flex items-center justify-between mb-2">
                    <h4 className="font-semibold">{theme.name}</h4>
                    <div className="flex items-center gap-2">
                      <Badge variant="secondary">{theme.count} mentions</Badge>
                      <Badge
                        variant={theme.sentiment > 0.3 ? 'default' : theme.sentiment < -0.3 ? 'destructive' : 'secondary'}
                      >
                        {theme.sentiment > 0.3 ? 'Positive' : theme.sentiment < -0.3 ? 'Negative' : 'Neutral'}
                      </Badge>
                    </div>
                  </div>
                  {theme.examples.length > 0 && (
                    <div className="space-y-1">
                      {theme.examples.slice(0, 2).map((example, i) => (
                        <p key={i} className="text-sm text-muted-foreground italic">
                          &ldquo;{example}&rdquo;
                        </p>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Recommendations */}
      {results.recommendations.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>AI Recommendations</CardTitle>
            <CardDescription>Action items based on feedback analysis</CardDescription>
          </CardHeader>
          <CardContent>
            <ol className="space-y-3">
              {results.recommendations.map((rec, index) => (
                <li key={index} className="flex gap-3">
                  <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-primary text-xs text-primary-foreground font-medium">
                    {index + 1}
                  </span>
                  <p className="text-sm text-muted-foreground">{rec}</p>
                </li>
              ))}
            </ol>
          </CardContent>
        </Card>
      )}
    </div>
  );
}
"}

{"content":"import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { analyzeFeedback } from '@/lib/openai';

export const maxDuration = 60;

export async function POST(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: surveyId } = await params;
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    // Get survey
    const { data: survey } = await supabase
      .from('surveys')
      .select('*')
      .eq('id', surveyId)
      .single();

    if (!survey) {
      return NextResponse.json({ error: 'Survey not found' }, { status: 404 });
    }

    // Get responses
    const { data: responses } = await supabase
      .from('survey_responses')
      .select('*')
      .eq('survey_id', surveyId);

    if (!responses?.length) {
      return NextResponse.json({ error: 'No responses to analyze' }, { status: 400 });
    }

    // Extract text responses for analysis
    const textResponses = responses.map((r) => {
      const answers = r.answers as Record<string, string | number | string[]>;
      return Object.entries(answers)
        .map(([qId, answer]) => {
          const question = survey.questions.find((q: { id: string }) => q.id === qId);
          const qText = question?.text || qId;
          return `Q: ${qText}\nA: ${Array.isArray(answer) ? answer.join(', ') : answer}`;
        })
        .join('\n');
    });

    // Run AI analysis
    const results = await analyzeFeedback(textResponses, 'full');

    // Save analysis
    const { data: analysis, error } = await supabase
      .from('analyses')
      .insert({
        survey_id: surveyId,
        analysis_type: 'full',
        results,
        model_used: 'gpt-4o',
      })
      .select()
      .single();

    if (error) return NextResponse.json({ error: error.message }, { status: 500 });

    return NextResponse.json({ data: analysis });
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Analysis failed';
    return NextResponse.json({ error: message }, { status: 500 });
  }
}
"}

{"content":"'use client';

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend } from 'recharts';

const COLORS = ['#3b82f6', '#8b5cf6', '#ec4899', '#f59e0b', '#10b981', '#6366f1', '#f43f5e', '#14b8a6'];

interface ResponseChartProps {
  question: {
    id: string;
    text: string;
    type: string;
    options?: string[];
  };
  answers: (string | number | string[])[];
}

export function ResponseChart({ question, answers }: ResponseChartProps) {
  if (question.type === 'rating' || question.type === 'nps') {
    const counts: Record<string, number> = {};
    answers.forEach((a) => {
      const key = String(a);
      counts[key] = (counts[key] || 0) + 1;
    });

    const max = question.type === 'nps' ? 10 : 5;
    const data = Array.from({ length: max }, (_, i) => ({
      name: String(i + (question.type === 'nps' ? 0 : 1)),
      count: counts[String(i + (question.type === 'nps' ? 0 : 1))] || 0,
    }));

    const avg = answers.length > 0
      ? (answers.reduce((sum: number, a) => sum + Number(a), 0) / answers.length).toFixed(1)
      : '0';

    return (
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium">{question.text}</CardTitle>
          <p className="text-2xl font-bold">{avg} <span className="text-sm font-normal text-muted-foreground">avg</span></p>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={data}>
              <XAxis dataKey="name" fontSize={12} />
              <YAxis fontSize={12} allowDecimals={false} />
              <Tooltip />
              <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>
    );
  }

  if (question.type === 'multiple_choice' || question.type === 'single_choice' || question.type === 'yes_no') {
    const counts: Record<string, number> = {};
    answers.forEach((a) => {
      if (Array.isArray(a)) {
        a.forEach((v) => { counts[v] = (counts[v] || 0) + 1; });
      } else {
        const key = String(a);
        counts[key] = (counts[key] || 0) + 1;
      }
    });

    const data = Object.entries(counts).map(([name, value]) => ({ name, value }));

    return (
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium">{question.text}</CardTitle>
          <p className="text-xs text-muted-foreground">{answers.length} responses</p>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={data} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={80} label>
                {data.map((_, i) => (
                  <Cell key={i} fill={COLORS[i % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>
    );
  }

  // Open-ended: just show count
  return (
    <Card>
      <CardHeader className="pb-2">
        <CardTitle className="text-sm font-medium">{question.text}</CardTitle>
      </CardHeader>
      <CardContent>
        <p className="text-2xl font-bold">{answers.length}</p>
        <p className="text-xs text-muted-foreground">text responses</p>
      </CardContent>
    </Card>
  );
}
"}

{"content":"import OpenAI from 'openai';

let _openai: OpenAI | null = null;

function getOpenAI(): OpenAI {
  if (!_openai) {
    _openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY,
    });
  }
  return _openai;
}

export async function extractFromDocument(
  imageBase64: string,
  prompt: string
): Promise<Record<string, { value: string | number | boolean | null; confidence: number }>> {
  const response = await getOpenAI().chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: 'You are a document data extraction specialist. Extract structured data from document images. Always respond with valid JSON only.',
      },
      {
        role: 'user',
        content: [
          {
            type: 'image_url',
            image_url: {
              url: `data:image/png;base64,${imageBase64}`,
              detail: 'high',
            },
          },
          {
            type: 'text',
            text: prompt,
          },
        ],
      },
    ],
    response_format: { type: 'json_object' },
    max_tokens: 4096,
  });

  const content = response.choices[0]?.message?.content;
  if (!content) throw new Error('No response from OpenAI');

  return JSON.parse(content);
}

export async function analyzeFeedback(
  responses: string[],
  analysisType: 'themes' | 'sentiment' | 'summary' | 'full' = 'full'
): Promise<Record<string, unknown>> {
  const systemPrompts: Record<string, string> = {
    themes: 'Identify the main themes and topics from survey responses. Return JSON with themes array containing name, count, sentiment score (-1 to 1), and example quotes.',
    sentiment: 'Analyze the sentiment distribution of survey responses. Return JSON with positive, neutral, negative percentages and overall sentiment score.',
    summary: 'Provide an executive summary of survey responses. Return JSON with summary text, key insights array, and recommendations array.',
    full: `Perform a comprehensive analysis of survey responses. Return JSON with:
- "summary": executive summary string
- "sentiment": {"positive": float, "neutral": float, "negative": float}
- "themes": [{"name": string, "count": int, "sentiment": float, "examples": string[]}]
- "recommendations": string[]
- "key_insights": string[]`,
  };

  const response = await getOpenAI().chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: systemPrompts[analysisType] || systemPrompts.full,
      },
      {
        role: 'user',
        content: `Analyze these ${responses.length} survey responses:\n\n${responses.map((r, i) => `Response ${i + 1}: ${r}`).join('\n\n')}`,
      },
    ],
    response_format: { type: 'json_object' },
    max_tokens: 4096,
  });

  const content = response.choices[0]?.message?.content;
  if (!content) throw new Error('No response from OpenAI');

  return JSON.parse(content);
}
"}

{"content":"// Database types
export interface Profile {
  id: string;
  email: string;
  full_name: string | null;
  avatar_url: string | null;
  created_at: string;
  updated_at: string;
}

export interface Organization {
  id: string;
  name: string;
  slug: string;
  stripe_customer_id: string | null;
  stripe_subscription_id: string | null;
  plan: 'free' | 'pro' | 'enterprise';
  plan_period_end: string | null;
  doc_quota: number;
  survey_quota: number;
  doc_used: number;
  survey_used: number;
  created_at: string;
}

export interface OrganizationMember {
  id: string;
  organization_id: string;
  user_id: string;
  role: 'owner' | 'admin' | 'member';
  created_at: string;
  profile?: Profile;
}

export interface Document {
  id: string;
  organization_id: string;
  uploaded_by: string;
  file_name: string;
  file_url: string;
  file_size: number | null;
  file_type: string | null;
  status: 'pending' | 'processing' | 'completed' | 'failed';
  extracted_data: Record<string, ExtractedField> | null;
  template_id: string | null;
  processing_time_ms: number | null;
  created_at: string;
  uploader?: Profile;
}

export interface ExtractedField {
  value: string | number | boolean | null;
  confidence: number;
}

export interface ExtractionTemplate {
  id: string;
  organization_id: string;
  name: string;
  description: string | null;
  fields: TemplateField[];
  category: 'invoice' | 'contract' | 'receipt' | 'custom' | null;
  is_default: boolean;
  created_at: string;
}

export interface TemplateField {
  name: string;
  type: 'text' | 'number' | 'date' | 'currency' | 'boolean';
  description: string;
  required?: boolean;
}

export interface Survey {
  id: string;
  organization_id: string;
  created_by: string;
  title: string;
  description: string | null;
  questions: SurveyQuestion[];
  status: 'draft' | 'active' | 'closed';
  settings: SurveySettings;
  response_count: number;
  created_at: string;
  updated_at: string;
}

export interface SurveyQuestion {
  id: string;
  type: 'open_ended' | 'multiple_choice' | 'single_choice' | 'rating' | 'nps' | 'yes_no';
  text: string;
  options?: string[];
  required: boolean;
  description?: string;
}

export interface SurveySettings {
  anonymous: boolean;
  allowMultiple: boolean;
  closeDate: string | null;
  thankYouMessage?: string;
}

export interface SurveyResponse {
  id: string;
  survey_id: string;
  answers: Record<string, string | number | string[]>;
  respondent_email: string | null;
  metadata: Record<string, unknown> | null;
  created_at: string;
}

export interface Analysis {
  id: string;
  survey_id: string;
  analysis_type: 'themes' | 'sentiment' | 'summary' | 'full';
  results: AnalysisResults;
  model_used: string;
  tokens_used: number | null;
  created_at: string;
}

export interface AnalysisResults {
  summary: string;
  sentiment: {
    positive: number;
    neutral: number;
    negative: number;
  };
  themes: AnalysisTheme[];
  recommendations: string[];
  nps_score?: number;
}

export interface AnalysisTheme {
  name: string;
  count: number;
  sentiment: number;
  examples: string[];
}

export interface ApiKey {
  id: string;
  organization_id: string;
  name: string;
  key_prefix: string;
  key_hash: string;
  last_used_at: string | null;
  expires_at: string | null;
  created_at: string;
}

export interface ActivityLog {
  id: string;
  organization_id: string;
  user_id: string | null;
  action: string;
  resource_type: 'document' | 'survey' | 'template' | null;
  resource_id: string | null;
  metadata: Record<string, unknown> | null;
  created_at: string;
}

// API types
export interface ApiResponse<T = unknown> {
  data?: T;
  error?: string;
  message?: string;
}

